81→export function requireE2BSandboxId(
82→  e2bSandboxId: string | null | undefined,
83→): string {
84→  if (!e2bSandboxId?.trim()) throw new Error("Sandbox is not provisioned yet");
85→  return e2bSandboxId.trim();
86→}
