88→export async function getSandboxRuntime(
89→  sandboxId: string,
90→  // userId: string,
91→  organizationId: string,
92→): Promise<Sandbox> {
93→  // const sandbox = await sandboxRepo.findById(sandboxId, userId);
94→  const sandbox = await sandboxRepo.findById(sandboxId, organizationId);
95→  if (!sandbox) throw new Error("Sandbox not found");
96→  const e2bSandboxId = requireE2BSandboxId(sandbox.e2bSandboxId);
97→  return connectSandbox(e2bSandboxId);
98→}
